# Check for model config / auth profiles  
find /root/.openclaw -name "*.json" -not -path "*/node_modules/*" -not -path "*/agents/*/sessions/*" | while read f; do
  if grep -qiE '"api[_-]?key"|"apiKey"|"api-key"|"token"|"secret"|"password"' "$f" 2>/dev/null; then
    echo "=== $f ==="
    python3 -c "
import json
with open('$f') as fh:
    try:
        d = json.load(fh)
    except:
        print('  (not json)')
        import sys; sys.exit(0)
def find_secrets(obj, path=''):
    if isinstance(obj, dict):
        for k, v in obj.items():
            kl = k.lower().replace('_','').replace('-','')
            if any(x in kl for x in ['apikey','token','secret','password','apikey']):
                if isinstance(v, str) and len(v) > 4:
                    val = v[:12]+'...'+v[-4:] if v[:4] != '${' else v
                    print(f'  {path}.{k} = {val}')
            find_secrets(v, f'{path}.{k}')
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            find_secrets(v, f'{path}[{i}]')
find_secrets(d)
" 2>/dev/null
  fi
done

