python3 << 'PYEOF'
import json, os

root = "/root/.openclaw"
exempt_patterns = ['node_modules', 'sessions', '.git', 'mcporter.json']  # mcporter is standalone

def find_plaintext_secrets(fp, d, path=""):
    found = []
    if isinstance(d, dict):
        for k, v in d.items():
            kl = k.lower().replace('_','').replace('-','')
            is_secret_field = any(x in kl for x in ['apikey','botoken','token','secret','password'])
            newpath = f"{path}.{k}"
            if is_secret_field and isinstance(v, str) and len(v) > 4:
                if not v.startswith('{') and not v.startswith('$'):
                    found.append((fp, newpath, v[:10]+'...'+v[-4:]))
            found.extend(find_plaintext_secrets(fp, v, newpath))
    elif isinstance(d, list):
        for i, v in enumerate(d):
            found.extend(find_plaintext_secrets(fp, v, f"{path}[{i}]"))
    return found

all_found = []
for dirpath, dirnames, filenames in os.walk(root):
    if any(p in dirpath for p in exempt_patterns):
        continue
    for fn in filenames:
        if not fn.endswith('.json'):
            continue
        fp = os.path.join(dirpath, fn)
        if any(p in fp for p in exempt_patterns):
            continue
        try:
            with open(fp) as f:
                d = json.load(f)
            all_found.extend(find_plaintext_secrets(fp, d))
        except:
            pass

if all_found:
    print("⚠️  PLAINTEXT SECRETS STILL FOUND:")
    for fp, field, val in sorted(set(all_found)):
        print(f"  {fp}\n    {field} = {val}")
else:
    print("✅ No plaintext secrets found in config files")

# Also check .env for the 4GEEKS_TOKEN suffix issue
with open('/root/.openclaw/.env') as f:
    for line in f:
        if '4GEEKS_TOKEN' in line and '=' in line:
            val = line.split('=', 1)[1].strip()
            print(f"\nℹ️  4GEEKS_TOKEN length: {len(val)} chars")
PYEOF

